/**
 * MedX tabs runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Manages tab panels for inventory, orders, compliance, and analytics views.
 */
const TAB_PANELS = Object.freeze({
  inventory: { label: "Inventory", icon: "package", lazy: false },
  orders: { label: "Orders", icon: "truck", lazy: true },
  suppliers: { label: "Suppliers", icon: "building", lazy: true },
  compliance: { label: "Compliance", icon: "shield", lazy: true },
  analytics: { label: "Analytics", icon: "chart", lazy: true },
  settings: { label: "Settings", icon: "gear", lazy: false },
});

const tabControllers = new Map();

function createTabController(id, panelKeys, options = {}) {
  const panels = panelKeys.map((key) => {
    const meta = TAB_PANELS[key];
    if (!meta) throw new Error(`Unknown tab panel: ${key}`);
    return {
      key,
      ...meta,
      mounted: !meta.lazy,
      contentLoaded: !meta.lazy,
    };
  });

  const controller = {
    id,
    panels,
    activeKey: options.defaultActive ?? panels[0]?.key ?? null,
    orientation: options.orientation ?? "horizontal",
    variant: options.variant ?? "underline",
    history: [],
    onTabChange: typeof options.onTabChange === "function" ? options.onTabChange : null,
  };
  tabControllers.set(id, controller);
  return controller;
}

function activateTab(controllerId, key) {
  const controller = tabControllers.get(controllerId);
  if (!controller) return false;
  const panel = controller.panels.find((p) => p.key === key);
  if (!panel) return false;

  const previous = controller.activeKey;
  controller.history.push({ from: previous, to: key, at: Date.now() });
  controller.activeKey = key;
  panel.mounted = true;

  if (panel.lazy && !panel.contentLoaded) {
    panel.contentLoaded = true;
    panel.loadedAt = Date.now();
  }

  if (controller.onTabChange) {
    controller.onTabChange({ previous, current: key, panel });
  }
  return true;
}

function getTabAriaAttributes(controllerId) {
  const controller = tabControllers.get(controllerId);
  if (!controller) return null;
  return controller.panels.map((panel) => ({
    tabId: `tab-${controllerId}-${panel.key}`,
    panelId: `panel-${controllerId}-${panel.key}`,
    selected: panel.key === controller.activeKey,
    controls: `panel-${controllerId}-${panel.key}`,
  }));
}

function getTabSnapshot(controllerId) {
  const controller = tabControllers.get(controllerId);
  if (!controller) return null;
  const active = controller.panels.find((p) => p.key === controller.activeKey);
  return {
    id: controller.id,
    activeKey: controller.activeKey,
    activeLabel: active?.label,
    panelCount: controller.panels.length,
    mountedPanels: controller.panels.filter((p) => p.mounted).length,
    historyLength: controller.history.length,
  };
}

async function runMedxTabs() {
  console.log("[medx:ui:tabs] runtime initialized");
  console.log(`[medx:ui:tabs] availablePanels=${Object.keys(TAB_PANELS).length}`);

  const dashboard = createTabController(
    "main-dashboard",
    ["inventory", "orders", "suppliers", "compliance", "analytics"],
    { defaultActive: "inventory" },
  );
  const settings = createTabController("settings-panel", ["settings"], {
    defaultActive: "settings",
    variant: "pills",
  });

  activateTab("main-dashboard", "orders");
  activateTab("main-dashboard", "compliance");
  activateTab("main-dashboard", "analytics");

  const aria = getTabAriaAttributes("main-dashboard");
  const snapshot = getTabSnapshot("main-dashboard");

  console.log(`[medx:ui:tabs] controllers=${tabControllers.size}`);
  console.log("[medx:ui:tabs] active", snapshot?.activeKey, "mounted", snapshot?.mountedPanels);
  console.log(`[medx:ui:tabs] ariaTabs=${aria?.length}`);
  console.log("[medx:ui:tabs] bootstrap complete");
}

module.exports = runMedxTabs;
